import clsx from 'clsx';
import {
  ResponsiveContainer, BarChart, Bar, XAxis, YAxis,
  CartesianGrid, Tooltip, Cell,
} from 'recharts';
import { useTheme } from '../../context/ThemeContext';
import { VEHICLE_TYPES } from '../../data/realData';

const maxCount = Math.max(...VEHICLE_TYPES.map(v => v.count));

function CustomTooltip({ active, payload, isDark }) {
  if (!active || !payload?.length) return null;
  const d = payload[0]?.payload;
  return (
    <div className={clsx(
      'px-3 py-2 rounded-lg text-xs shadow-xl border',
      isDark ? 'bg-navy-600 border-navy-500 text-gray-200' : 'bg-white border-gray-200 text-gray-700'
    )}>
      <p className="font-semibold">{d.name}</p>
      <p style={{ color: d.color }}>{d.count.toLocaleString()} violations</p>
      <p className={isDark ? 'text-gray-400' : 'text-gray-500'}>
        {((d.count / VEHICLE_TYPES.reduce((s, v) => s + v.count, 0)) * 100).toFixed(1)}% of total
      </p>
    </div>
  );
}

export default function VehicleTypeChart() {
  const { isDark } = useTheme();

  return (
    <div className={clsx(
      'rounded-xl border p-4',
      isDark ? 'bg-navy-700 border-navy-600/30' : 'bg-white border-gray-200 shadow-sm'
    )}>
      <div className="flex items-center justify-between mb-3">
        <h3 className={clsx('text-sm font-semibold', isDark ? 'text-gray-200' : 'text-gray-800')}>
          Violations by Vehicle Type
        </h3>
      </div>

      <ResponsiveContainer width="100%" height={220}>
        <BarChart
          data={VEHICLE_TYPES}
          layout="vertical"
          margin={{ top: 5, right: 10, bottom: 5, left: 60 }}
        >
          <CartesianGrid strokeDasharray="3 3" stroke="rgba(99,140,190,0.08)" horizontal={false} />
          <XAxis
            type="number"
            tick={{ fontSize: 9, fill: isDark ? '#6B7280' : '#9CA3AF' }}
            stroke="transparent"
            tickLine={false}
            tickFormatter={v => v >= 1000 ? `${(v / 1000).toFixed(0)}k` : v}
          />
          <YAxis
            type="category"
            dataKey="name"
            tick={{ fontSize: 10, fill: isDark ? '#9CA3AF' : '#6B7280' }}
            stroke="transparent"
            tickLine={false}
            width={56}
          />
          <Tooltip content={<CustomTooltip isDark={isDark} />} />
          <Bar dataKey="count" radius={[0, 4, 4, 0]} maxBarSize={14}>
            {VEHICLE_TYPES.map((entry, i) => (
              <Cell key={i} fill={entry.color} opacity={0.8} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}

import { useEffect, useRef, useState } from 'react';
import { TrendingUp } from 'lucide-react';
import * as LucideIcons from 'lucide-react';
import clsx from 'clsx';
import { useTheme } from '../../context/ThemeContext';

const COLOR_MAP = {
  blue:   { bg: 'bg-blue-500/15',   icon: 'text-brand-blue'   },
  orange: { bg: 'bg-orange-500/15', icon: 'text-brand-orange' },
  teal:   { bg: 'bg-cyan-500/15',   icon: 'text-brand-cyan'   },
  purple: { bg: 'bg-purple-500/15', icon: 'text-brand-purple' },
};

function useCountUp(target, duration = 1200) {
  const [count, setCount] = useState(0);
  const rafRef = useRef(null);

  useEffect(() => {
    const start = performance.now();
    const easeOutQuart = t => 1 - Math.pow(1 - t, 4);

    const tick = now => {
      const elapsed = now - start;
      const progress = Math.min(elapsed / duration, 1);
      setCount(Math.round(easeOutQuart(progress) * target));
      if (progress < 1) rafRef.current = requestAnimationFrame(tick);
    };

    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, [target, duration]);

  return count;
}

export default function KPICard({ label, value, change, changeLabel, positive, icon, color }) {
  const { isDark } = useTheme();
  const displayValue = useCountUp(value);
  const Icon = LucideIcons[icon] || LucideIcons.Activity;
  const colors = COLOR_MAP[color] || COLOR_MAP.blue;

  return (
    <div className={clsx(
      'flex items-center justify-between p-5 rounded-xl border transition-all duration-200 hover:scale-[1.01]',
      isDark
        ? 'bg-navy-700 border-navy-600/30'
        : 'bg-white border-gray-200 shadow-sm'
    )}>
      {/* Left */}
      <div className="flex-1 min-w-0">
        <p className={clsx('text-xs font-medium mb-2 truncate', isDark ? 'text-gray-400' : 'text-gray-500')}>
          {label}
        </p>
        <p className={clsx('text-3xl font-bold tracking-tight tabular-nums', isDark ? 'text-gray-100' : 'text-gray-900')}>
          {displayValue.toLocaleString()}
        </p>
        <div className="flex items-center gap-1 mt-1.5">
          <TrendingUp size={12} className="text-green-400 flex-shrink-0" />
          <span className="text-xs text-green-400 font-medium">{change}</span>
          <span className={clsx('text-xs', isDark ? 'text-gray-500' : 'text-gray-400')}>{changeLabel}</span>
        </div>
      </div>

      {/* Right — icon */}
      <div className={clsx('w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0 ml-3', colors.bg)}>
        <Icon size={22} className={colors.icon} />
      </div>
    </div>
  );
}

