      map,
      center: { lat: cluster.lat, lng: cluster.lng },
      radius: 300,
      fillColor: color,
      fillOpacity: isSelected ? 0.45 : 0.25,
      strokeColor: color,
      strokeOpacity: isSelected ? 1.0 : 0.75,
      strokeWeight: isSelected ? 2.5 : 1.5,
